INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (1, N'Fujifilm X-T30 Mark II Hàng cũ, giá tốt', N'Fujifilm X-T30 Mark II hàng cũ chất lượng. Sản phẩm qua sử dụng giá bán đã bao gồm thuế VAT. Máy ảnh vẫn mang vẻ ngoài cổ điển thể thao, có các nút điều khiển vật lý nổi bật và có kính ngắm điện tử OLED độ phân giải cao 2,36m. Màn hình LCD cảm ứng nghiêng', 21490000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_1_Fujifilm_X-T30_Mark_II_H_ng_c___gi__t_t.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (2, N'Fujifilm X-T100 Hàng cũ | Máy ảnh Fujifilm X-T100 qua sử dụng', N'Máy ảnh X-T100 cũ được trang bị cảm biến CMOS 24.2MP APS-C cho phép ghi hình ảnh tĩnh và video có độ phân giải cao trong nhiều điều kiện ánh sáng khác nhau. Dải từ ISO 200-12800, có thể được mở rộng thành ISO 100-51200 để phù hợp hơn trong các trường hợp', 14990000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_2_Fujifilm_X-T100_H_ng_c____M_y__nh_Fujifilm_X-T100_.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (3, N'Sony A7C Hàng cũ Chính hãng, giá tốt', N'Sony a7C hàng cũ là một máy ảnh Mirrorless Full Frame nhỏ gọn sở hữu cảm biến 24MP và ổn định hình ảnh 5 trục. Có cùng hệ thống lấy nét tự động lai giống như trên các mẫu máy cao cấp hơn, có tính năng &amp;quot;Real-time Tracking&amp;quot; và &amp;quot;Eye AF&#039; cho cả', 24990000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_3_Sony_A7C_H_ng_c__Ch_nh_h_ng__gi__t_t.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (4, N'Canon EOS M50 Hàng cũ | Máy ảnh Canon M50 qua sử dụng', N'Canon EOS M50 hàng qua sử dụng tiết kiệm hơn. Với bộ cảm biến CMOS APS-C CMOS 24.1MP và bộ xử lý hình ảnh DIGIC 8 để mang lại độ nhạy cao và hiệu suất chụp ảnh nhanh phù hợp với cả ảnh tĩnh và các ứng dụng quay video. Khoảng cách ISO vượt trội từ 100-2560', 12990000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_4_Canon_EOS_M50_H_ng_c____M_y__nh_Canon_M50_qua_s__d.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (5, N'Canon EOS R50 Màu trắng sản phẩm chính hãng', N'Canon EOS R50 trang bị chip xử lý hình ảnh DIGIC X đáp ứng nhiều tác vụ tốc độ cao, từ chụp liên tiếp nhanh đến quay phim phân giải cao. R50 hỗ trợ chụp liên tiếp tốc độ cao đến 23 fps với màn trập điện tử không ồn', 17990000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_5_Canon_EOS_R50_M_u_tr_ng_s_n_ph_m_ch_nh_h_ng.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (6, N'Máy ảnh Nikon Z5 Mark II | Chính hãng, Giá tốt', N'Máy ảnh Nikon Z5 II không chỉ dành cho nhiếp ảnh – Khả năng quay video cũng được nâng cấp vượt trội. Máy hỗ trợ quay UHD 4K ở 60 fps và Full HD lên tới 120 fps, với thời lượng ghi hình tối đa lên đến 2 giờ.', 40790000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_6_M_y__nh_Nikon_Z5_Mark_II___Ch_nh_h_ng__Gi__t_t.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (7, N'Máy ảnh Fujifilm X-S20 kèm ống kính XF 16-50mm Chính hãng', N'Máy ảnh Fujifilm X-S20 kèm ống kính XF 16-50mm trang bị công nghệ chống rung IBIS 5 trục bên trong thân máy mang lại những Shot hình sắc nét ấn tượng ngay cả khi quay chụp trong điều kiện ánh sáng yếu hoặc sử dụng tốc độ màn trập chậm hơn.', 46490000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_7_M_y__nh_Fujifilm_X-S20_k_m__ng_k_nh_XF_16-50mm_Ch_.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (8, N'Fujifilm X-S20 kèm Ống kính XC 15-45mm Chính hãng', N'Fujifilm X-S20 kèm Ống kính XC 15-45mm sở hữu thiết kế đặc trưng của dòng XS với báng cầm lớn mang lại cảm giác cầm nắm dễ dàng. Trọng lượng máy ảnh chỉ 491 Gram, người dùng dễ dàng cho chiếc Camera vào Balo và mang theo trong những chuyến đi của mình.', 37490000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_8_Fujifilm_X-S20_k_m__ng_k_nh_XC_15-45mm_Ch_nh_h_ng.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (9, N'Máy ảnh Fujifilm X-S20 Chính hãng, Giá tốt', N'Máy ảnh Fujifilm X-S20 trang bị cảm biến 26.1MP X-Trans CMOS 4 kết hợp bộ xử lý hình ảnh X-Processor 5, chống rung IBIS 7 Stop, lấy nét tự động bằng AI vượt trội, mang lại những thước phim chất lượng 6.2K30fps ấn tượng.', 34490000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_9_M_y__nh_Fujifilm_X-S20_Ch_nh_h_ng__Gi__t_t.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (10, N'Fujifilm X-T30 III Phiên Bản Nâng Cấp Dòng X-T30 Series', N'Phiên bản Fujifilm X-T30 III kế thừa tinh hoa từ X-T30 II với hiệu năng cải thiện, xử lý nhanh hơn và màu sắc chuẩn phim điện ảnh của Fujifilm. Máy có thiết kế nhỏ gọn, phong cách cổ điển, cảm biến 26.1MP, quay 6.2K, lấy nét AI cực nhanh.', 26490000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_10_Fujifilm_X-T30_III_Phi_n_B_n_N_ng_C_p_D_ng_X-T30_S.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (11, N'Canon 600D Hàng cũ | Mayanh24h', N'canon 600D có màn hình LCD 3.0 inch sắc nét được thiết kế đặc biệt kiểu khớp nối với khả năng xoay linh hoạt cho phép bạn xoay màn hình ở hầu hết các góc chụp với độ phân giải lên tới 18Megapixel.', 4900000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_11_Canon_600D_H_ng_c____Mayanh24h.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (12, N'Canon PowerShot G7X Mark III Quay Vlog Nhỏ Gọn, Chất Lượng 4K', N'Canon G7X Mark III là chiếc máy ảnh compact lý tưởng cho vlogger và nhà sáng tạo nội dung, với khả năng quay video 4K, livestream trực tiếp, cảm biến 1 inch và thiết kế nhỏ gọn tiện dụng.', 28990000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_12_Canon_PowerShot_G7X_Mark_III_Quay_Vlog_Nh__G_n__Ch.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (13, N'Sony A7S Mark III: Quái Vật Quay Phim Full-Frame Đỉnh Cao', N'Sony A7S Mark III là lựa chọn hàng đầu cho quay phim chuyên nghiệp với cảm biến full-frame 12.1MP, quay video 4K 120fps, dải dynamic range lên đến 15+ stops, chống rung 5 trục, lấy nét nhanh và chính xác trong mọi điều kiện ánh sáng.', 75500000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_13_Sony_A7S_Mark_III__Qu_i_V_t_Quay_Phim_Full-Frame__.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (14, N'Canon EOS R Hàng cũ | Máy ảnh Canon EOS R', N'Canon EOS R qua sử dụng là mẫu máy ảnh Full-Frame Mirrorless được trang bị cảm biến CMOS Dual Pixel AF 30.3 Million Pixels. Các tính năng bao gồm độ phủ AF lớn (100% theo chiều dọc và ngang 88%), lấy nét tự động ánh sáng thấp EV -6, quay video 4K, Wi-Fi,', 17900000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_14_Canon_EOS_R_H_ng_c____M_y__nh_Canon_EOS_R.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (15, N'Canon 5D Mark III Hàng cũ, giá tốt', N'Máy ảnh Canon 5D Mark III trang bị cảm biến CMOS full-frame kích thước 36x24mm có độ phân giải nhỉnh hơn Mark II một chút, 22.3 Megapixel. Tuy vậy, chất lượng hình ảnh được đánh giá rõ nét hơn, tuyệt vời hơn người tiền nhiệm Mark II do cảm biến mới có nh', 8990000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_15_Canon_5D_Mark_III_H_ng_c___gi__t_t.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (16, N'Sony A7 Mark IV Hàng cũ | Chính hãng, giá tốt', N'Sony A7 Mark IV hàng cũ chất lượng sản phẩm được kiểm tra chặc chẽ, giá hàng cũ đã gồm thuế VAT, là chiếc máy ảnh Fullframe với cảm biến 30MP tích hợp chống rung quang học 5 trục, Chụp 10 khung hình / giây với theo dõi AF / AE đầy đủ.', 38500000.00, 10, N'/uploads/products/may-anh-dslr/may-anh-dslr_16_Sony_A7_Mark_IV_H_ng_c____Ch_nh_h_ng__gi__t_t.jpg', 1);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (17, N'Tamron 17-70mm f/2.8 Di III-A VC RXD for Sony | Chính hãng, giá tốt', N'Tamron 17-70mm f/2.8 Di III-A VC RXD cho phép chụp đa dạng thể loại từ góc rộng đến Telephoto với phạm vi tiêu cự 17mm đến 70mm. Tamron 17-70mm F/2.8 bao gồm 16 thấu kính chia làm 12 nhóm. Cùng với 2 thấu kính GM', 12990000.00, 10, N'/uploads/products/ong-kinh/ong-kinh_1_Tamron_17-70mm_f_2_8_Di_III-A_VC_RXD_for_Sony___Ch.jpg', 2);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
