INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (19, N'Ống kính Sony FE 24-70mm F2.8 GM hàng cũ', N'Ống kính Sony FE 24-70mm F2.8 GM dòng lens cao cấp dòng G Master cố định chụp tele tầm trung, Ống kính Sony có lớp phủ Nano AR giúp loại bỏ hiện tượng chói và bóng mờ, Khẩu độ tròn 9 lá đem lại các hiệu ứng làm mờ đẹp mắt', 25490000.00, 10, N'/uploads/products/ong-kinh/ong-kinh_5__ng_k_nh_Sony_FE_24-70mm_F2_8_GM_h_ng_c_.jpg', 2);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (20, N'Sony CZ 16-70mm F4 Hàng cũ | Sony CZ 16-70mm F4 | Sony 16-70mm | Mayanh24h', N'Sony CZ 16-70mm F4 ZA Vario-Tessar® T* OSS Ống kính zoom tầm trung gọn nhẹ này là sự kết hợp giữa hiệu suất quang học ZEISS nổi tiếng với khẩu độ tối đa F4 cố định cho hiệu suất vượt trội trên mọi khía cạnh. Động cơ tuyến tính giúp tạo sự êm ả', 8490000.00, 10, N'/uploads/products/ong-kinh/ong-kinh_6_Sony_CZ_16-70mm_F4_H_ng_c____Sony_CZ_16-70mm_F4___.jpg', 2);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (21, N'Canon RF 70-200mm f/4L IS USM hàng cũ', N'Ống kính Canon RF 70-200mm f/4L IS USM là một trong những thành viên được kính nể trong nhóm ống kính 70-200mm của Canon với những trang bị cao cấp như khẩu độ f/4.0', 28990000.00, 10, N'', 2);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (22, N'Sony E 15mm f/1.4 G hàng cũ chính hãng giá rẻ', N'Sony E 15mm f/1.4 G hàng cũ là ống kính một tiêu cự góc rộng nhỏ gọn tương thích với máy ảnh Sony Alpha hệ APS-C. Tuyệt vời cho những người đam mê quay Vlog, Selfie, chụp kiến trúc và chụp phong cảnh góc rộng.', 10990000.00, 10, N'/uploads/products/ong-kinh/ong-kinh_8_Sony_E_15mm_f_1_4_G_h_ng_c__ch_nh_h_ng_gi__r_.jpg', 2);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
