INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (25, N'Ống Kính Canon RF 100-400mm f/5.6-8 IS USM Chính Hãng, Giá Tốt', N'Canon RF 100-400mm f/5.6-8 IS USM nhỏ gọn, nhẹ, tích hợp chống rung quang học IS, lấy nét Nano USM nhanh và êm. Lý tưởng cho chụp thể thao, động vật hoang dã và du lịch. Mua ngay tại Mayanh24h với giá tốt!', 15490000.00, 10, N'/uploads/products/ong-kinh/ong-kinh_11__ng_K_nh_Canon_RF_100-400mm_f_5_6-8_IS_USM_Ch_nh_H.jpg', 2);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (26, N'Ống Kính Canon RF 24-70mm f/2.8L IS USM Chính Hãng Giá Tốt', N'Mua ống kính Canon RF 24-70mm f/2.8L IS USM chính hãng, khẩu độ f/2.8 toàn dải, chống rung IS, chụp ảnh sắc nét trong mọi điều kiện ánh sáng. Giá tốt, giao nhanh, bảo hành đầy đủ.', 48990000.00, 10, N'/uploads/products/ong-kinh/ong-kinh_12__ng_K_nh_Canon_RF_24-70mm_f_2_8L_IS_USM_Ch_nh_H_ng.jpg', 2);

