INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
VALUES (28, N'Viltrox AF 85mm F/1.4 PRO FE for Sony Hàng cũ, giá tốt', N'Ống kính Viltrox AF 85mm f/1.4 Pro FE hàng cũ, chất lượng sản phẩm qua sử dụng giá bán đã bao gồm thuế VAT. Lens sở hữu thiết kế chống bụi và chống nước nhẹ nhờ các vòng ron cao su đặt tại các vị trí trọng yếu, đảm bảo khả năng vận hành ổn định khi hoạt đ', 9990000.00, 10, N'/uploads/products/ong-kinh/ong-kinh_14_Viltrox_AF_85mm_F_1_4_PRO_FE_for_Sony_H_ng_c___gi_.jpg', 2);

INSERT INTO [Products] ([Id], [Name], [Description], [Price], [StockQuantity], [ImageUrl], [CategoryProductId])
